function MoodBoard() {
  const [items, setItems] = React.useState([
    { id: 1, label: 'Nature' },
    { id: 2, label: 'Architecture' },
    { id: 3, label: 'Texture' },
    { id: 4, label: 'Color' },
    { id: 5, label: 'Pattern' },
    { id: 6, label: 'Light' }
  ]);

  const colors = ['#e2e8f0', '#cbd5e1', '#94a3b8', '#64748b', '#475569', '#334155'];

  return (
    <div style={{ fontFamily: 'system-ui, sans-serif', padding: 16, background: '#ffffff', borderRadius: 12, height: '100%', display: 'flex', flexDirection: 'column', color: '#1e293b' }}>
      <h2 style={{ margin: '0 0 12px', fontSize: 18 }}>Mood Board</h2>
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: 8, flex: 1 }}>
        {items.map((item, i) => (
          <div key={item.id} style={{
            background: colors[i % colors.length],
            borderRadius: 8,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            textAlign: 'center',
            fontSize: 12,
            color: '#fff',
            fontWeight: 600,
            aspectRatio: '1',
            cursor: 'pointer'
          }}>
            {item.label}
          </div>
        ))}
      </div>
      <button onClick={() => setItems([...items, { id: Date.now(), label: 'New' }])} style={{ marginTop: 12, padding: '8px 12px', borderRadius: 6, border: 'none', background: '#2563eb', color: '#fff', fontSize: 13, cursor: 'pointer' }}>Add Slot</button>
    </div>
  );
}
render(<MoodBoard/>);
